import{_ as t,o as a,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Alert Notifications (New)","description":"","frontmatter":{"title":"Alert Notifications (New)","slug":"alert-notifications-new"},"headers":[],"relativePath":"account-hub/alert-notifications-new.md","filePath":"account-hub/alert-notifications-new.md"}'),o={name:"account-hub/alert-notifications-new.md"};function r(s,e,l,c,h,d){return a(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The alerting system lets you set up automatic email alerts on Branch to notify you of any data and account settings changes. This will help keep track of any unwanted account changes, reduce the chance of data loss, and increase visibility into postback flows.</p><p>Features include:</p><ul><li>Email alerts based on user role permissions and email address.</li><li>Admins enable specific account alerts.</li><li>Add recipient emails from Branch.</li><li>Unsubscribe directly from the email.</li><li>Track the last triggered alert.</li></ul><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Testing &amp; Monitoring page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h3 id="email-alerts" tabindex="-1">Email alerts <a class="header-anchor" href="#email-alerts" aria-label="Permalink to &quot;Email alerts&quot;">​</a></h3><p>Branch will notify those on the email list of the following alerts:</p><table tabindex="0"><thead><tr><th>Alert</th><th>Details</th></tr></thead><tbody><tr><td>SAN authentication token expiry</td><td>Notification if a SAN Authentication Token (used to establish a connection between Branch and a SAN) is expired. You can use this notification to reauthenticate the SAN connection.</td></tr><tr><td>Postback failures</td><td>Notification if the success rate of a postback falls below a configurable success threshold over a 24-hour period.</td></tr><tr><td>A change is made to the settings of an existing integrated SAN partner</td><td>Notification if there is a change in the settings of a SAN setting: - Change in authentication. - Change in Events Configuration. - Change in Attribution Windows.</td></tr><tr><td>A change is made to the global settings of an account</td><td>Notification if there is a change in the account configuration of Branch account settings: - Account Settings &gt; Profile. - Configuration &gt; General. - Configuration &gt; Attribution windows.</td></tr></tbody></table><h2 id="get-started" tabindex="-1">Get started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get started&quot;">​</a></h2><p>The Alert Notification system can be accessed through the <strong>Testing &amp; Monitoring</strong> screen on the <a href="https://branchdocs.app.link/alert-notifications" target="_blank" rel="noreferrer"><strong>Alert Notifications</strong></a> tab. For each alert, you can <strong>subscribe</strong>, <strong>configure recipients</strong>, and <strong>enable/disable alerts</strong> using the three-dot menu.</p><h3 id="alert-actions-menu" tabindex="-1">Alert actions menu <a class="header-anchor" href="#alert-actions-menu" aria-label="Permalink to &quot;Alert actions menu&quot;">​</a></h3><p>Select the three-dot menu icon on any alert row to access the following options:</p><ul><li><strong>Subscribe:</strong> Quickly add yourself to the list of recipients for the alert.</li><li><strong>Recipients:</strong> View and manage the full list of users receiving emails for the alert.</li><li><strong>Enable Alert / Disable Alert:</strong> Toggle the alert status between <strong>Active</strong> and <strong>Disabled</strong>.</li></ul><h3 id="subscribe" tabindex="-1">Subscribe <a class="header-anchor" href="#subscribe" aria-label="Permalink to &quot;Subscribe&quot;">​</a></h3><p><strong>Subscribe</strong> lets you quickly add yourself to the list of recipients of the alert.</p><h3 id="recipients" tabindex="-1">Recipients <a class="header-anchor" href="#recipients" aria-label="Permalink to &quot;Recipients&quot;">​</a></h3><p>Selecting <strong>Recipients</strong> will allow you to view the full list of users who are receiving emails for a given alert. Here you&#39;ll be able to add or remove recipients by role or by email address. Only admins can add other recipients, while individual users can subscribe themselves directly using the Subscribe option.</p><p>When adding recipients, you can choose to add by <strong>Role</strong> or by <strong>Email</strong>:</p><ul><li><strong>Role:</strong> Select from available roles including Admin, Team Member, Full Read, Limited Read, Custom, User Coordinator, or No Access.</li><li><strong>Email:</strong> Add multiple email addresses directly.</li></ul><h3 id="enable-disable-alert" tabindex="-1">Enable/disable alert <a class="header-anchor" href="#enable-disable-alert" aria-label="Permalink to &quot;Enable/disable alert&quot;">​</a></h3><p>Select <strong>Enable Alert</strong> or <strong>Disable Alert</strong> from the three-dot menu to change the status of the alert to <strong>Active</strong> or <strong>Disabled</strong>. Enabled alerts will allow those in the recipient list to receive emails for the given alert. Note, only admins of the Branch account can enable or disable alerts.</p>',21)])])}const b=t(o,[["render",r]]);export{g as __pageData,b as default};
